250	bitflags::bitflags! {
251	    /// Supported subgroup operations
252	    #[cfg_attr(feature = "serialize", derive(serde::Serialize))]
253	    #[cfg_attr(feature = "deserialize", derive(serde::Deserialize))]
254	    #[derive(Clone, Copy, Debug, Default, Eq, PartialEq)]
255	    pub struct SubgroupOperationSet: u8 {
256	        /// Barriers
257	        // Possibly elections, when that is supported.
258	        // https://github.com/gfx-rs/wgpu/issues/6042#issuecomment-3272603431
259	        // Contrary to what the name "basic" suggests, HLSL/DX12 support the
260	        // other subgroup operations, but do not support subgroup barriers.
261	        const BASIC = 1 << 0;
262	        /// Any, All
263	        const VOTE = 1 << 1;
264	        /// reductions, scans
265	        const ARITHMETIC = 1 << 2;
266	        /// ballot, broadcast
267	        const BALLOT = 1 << 3;
268	        /// shuffle, shuffle xor
269	        const SHUFFLE = 1 << 4;
270	        /// shuffle up, down
271	        const SHUFFLE_RELATIVE = 1 << 5;
272	        // We don't support these operations yet
273	        // /// Clustered
274	        // const CLUSTERED = 1 << 6;
275	        /// Quad supported
276	        const QUAD_FRAGMENT_COMPUTE = 1 << 7;
277	        // /// Quad supported in all stages
278	        // const QUAD_ALL_STAGES = 1 << 8;
279	    }
280	}
