282	impl super::SubgroupOperation {
283	    const fn required_operations(&self) -> SubgroupOperationSet {
284	        use SubgroupOperationSet as S;
285	        match *self {
286	            Self::All | Self::Any => S::VOTE,
287	            Self::Add | Self::Mul | Self::Min | Self::Max | Self::And | Self::Or | Self::Xor => {
288	                S::ARITHMETIC
289	            }
290	        }
291	    }
292	}
293	
294	impl super::GatherMode {
295	    const fn required_operations(&self) -> SubgroupOperationSet {
296	        use SubgroupOperationSet as S;
297	        match *self {
298	            Self::BroadcastFirst | Self::Broadcast(_) => S::BALLOT,
299	            Self::Shuffle(_) | Self::ShuffleXor(_) => S::SHUFFLE,
300	            Self::ShuffleUp(_) | Self::ShuffleDown(_) => S::SHUFFLE_RELATIVE,
301	            Self::QuadBroadcast(_) | Self::QuadSwap(_) => S::QUAD_FRAGMENT_COMPUTE,
302	        }
303	    }
304	}
