514	impl crate::TypeInner {
515	    const fn is_sized(&self) -> bool {
516	        match *self {
517	            Self::Scalar { .. }
518	            | Self::Vector { .. }
519	            | Self::Matrix { .. }
520	            | Self::CooperativeMatrix { .. }
521	            | Self::Array {
522	                size: crate::ArraySize::Constant(_),
523	                ..
524	            }
525	            | Self::Atomic { .. }
526	            | Self::Pointer { .. }
527	            | Self::ValuePointer { .. }
528	            | Self::Struct { .. } => true,
529	            Self::Array { .. }
530	            | Self::Image { .. }
531	            | Self::Sampler { .. }
532	            | Self::AccelerationStructure { .. }
533	            | Self::RayQuery { .. }
534	            | Self::BindingArray { .. } => false,
535	        }
536	    }
