538	    /// Return the `ImageDimension` for which `self` is an appropriate coordinate.
539	    const fn image_storage_coordinates(&self) -> Option<crate::ImageDimension> {
540	        match *self {
541	            Self::Scalar(crate::Scalar {
542	                kind: crate::ScalarKind::Sint | crate::ScalarKind::Uint,
543	                ..
544	            }) => Some(crate::ImageDimension::D1),
545	            Self::Vector {
546	                size: crate::VectorSize::Bi,
547	                scalar:
548	                    crate::Scalar {
549	                        kind: crate::ScalarKind::Sint | crate::ScalarKind::Uint,
550	                        ..
551	                    },
552	            } => Some(crate::ImageDimension::D2),
553	            Self::Vector {
554	                size: crate::VectorSize::Tri,
555	                scalar:
556	                    crate::Scalar {
557	                        kind: crate::ScalarKind::Sint | crate::ScalarKind::Uint,
558	                        ..
559	                    },
560	            } => Some(crate::ImageDimension::D3),
561	            _ => None,
562	        }
563	    }
