566	impl Validator {
567	    /// Create a validator for Naga [`Module`]s.
568	    ///
569	    /// The `flags` argument indicates which stages of validation the
570	    /// returned `Validator` should perform. Skipping stages can make
571	    /// validation somewhat faster, but the validator may not reject some
572	    /// invalid modules. Regardless of `flags`, validation always returns
573	    /// a usable [`ModuleInfo`] value on success.
574	    ///
575	    /// If `flags` contains everything in `ValidationFlags::default()`,
576	    /// then the returned Naga [`Validator`] will reject any [`Module`]
577	    /// that would use capabilities not included in `capabilities`.
578	    ///
579	    /// [`Module`]: crate::Module
580	    pub fn new(flags: ValidationFlags, capabilities: Capabilities) -> Self {
581	        let subgroup_operations = if capabilities.contains(Capabilities::SUBGROUP) {
582	            use SubgroupOperationSet as S;
583	            S::BASIC
584	                | S::VOTE
585	                | S::ARITHMETIC
586	                | S::BALLOT
587	                | S::SHUFFLE
588	                | S::SHUFFLE_RELATIVE
589	                | S::QUAD_FRAGMENT_COMPUTE
590	        } else {
591	            SubgroupOperationSet::empty()
592	        };
593	        let subgroup_stages = {
594	            let mut stages = ShaderStages::empty();
595	            if capabilities.contains(Capabilities::SUBGROUP_VERTEX_STAGE) {
596	                stages |= ShaderStages::VERTEX;
597	            }
598	            if capabilities.contains(Capabilities::SUBGROUP) {
599	                stages |= ShaderStages::FRAGMENT | ShaderStages::COMPUTE_LIKE;
600	            }
601	            stages
602	        };
603	
604	        Validator {
605	            flags,
606	            capabilities,
607	            subgroup_stages,
608	            subgroup_operations,
609	            types: Vec::new(),
610	            layouter: Layouter::default(),
611	            location_mask: BitSet::new(),
612	            ep_resource_bindings: FastHashSet::default(),
613	            switch_values: FastHashSet::default(),
614	            valid_expression_list: Vec::new(),
615	            valid_expression_set: HandleSet::new(),
616	            override_ids: FastHashSet::default(),
617	            overrides_resolved: false,
618	            needs_visit: HandleSet::new(),
619	            trace_rays_vertex_return: TraceRayVertexReturnState::NoTraceRays,
620	            trace_rays_payload_type: None,
621	        }
622	    }
623	
624	    // TODO(https://github.com/gfx-rs/wgpu/issues/8207): Consider removing this
625	    pub const fn subgroup_stages(&mut self, stages: ShaderStages) -> &mut Self {
626	        self.subgroup_stages = stages;
627	        self
628	    }
629	
630	    // TODO(https://github.com/gfx-rs/wgpu/issues/8207): Consider removing this
631	    pub const fn subgroup_operations(&mut self, operations: SubgroupOperationSet) -> &mut Self {
632	        self.subgroup_operations = operations;
633	        self
634	    }
635	
636	    /// Reset the validator internals
637	    pub fn reset(&mut self) {
638	        self.types.clear();
639	        self.layouter.clear();
640	        self.location_mask.make_empty();
641	        self.ep_resource_bindings.clear();
642	        self.switch_values.clear();
643	        self.valid_expression_list.clear();
644	        self.valid_expression_set.clear();
645	        self.override_ids.clear();
646	    }
647	
648	    fn validate_constant(
649	        &self,
650	        handle: Handle<crate::Constant>,
651	        gctx: crate::proc::GlobalCtx,
652	        mod_info: &ModuleInfo,
653	        global_expr_kind: &ExpressionKindTracker,
654	    ) -> Result<(), ConstantError> {
655	        let con = &gctx.constants[handle];
656	
657	        let type_info = &self.types[con.ty.index()];
658	        if !type_info.flags.contains(TypeFlags::CONSTRUCTIBLE) {
659	            return Err(ConstantError::NonConstructibleType);
660	        }
661	
662	        if !global_expr_kind.is_const(con.init) {
663	            return Err(ConstantError::InitializerExprType);
664	        }
665	
666	        if !gctx.compare_types(&TypeResolution::Handle(con.ty), &mod_info[con.init]) {
667	            return Err(ConstantError::InvalidType);
668	        }
669	
670	        Ok(())
671	    }
672	
673	    fn validate_override(
674	        &mut self,
675	        handle: Handle<crate::Override>,
676	        gctx: crate::proc::GlobalCtx,
677	        mod_info: &ModuleInfo,
678	    ) -> Result<(), OverrideError> {
679	        let o = &gctx.overrides[handle];
680	
681	        if let Some(id) = o.id {
682	            if !self.override_ids.insert(id) {
683	                return Err(OverrideError::DuplicateID);
684	            }
685	        }
686	
687	        let type_info = &self.types[o.ty.index()];
688	        if !type_info.flags.contains(TypeFlags::CONSTRUCTIBLE) {
689	            return Err(OverrideError::NonConstructibleType);
690	        }
691	
692	        match gctx.types[o.ty].inner {
693	            crate::TypeInner::Scalar(
694	                crate::Scalar::BOOL
695	                | crate::Scalar::I32
696	                | crate::Scalar::U32
697	                | crate::Scalar::F16
698	                | crate::Scalar::F32
699	                | crate::Scalar::F64,
700	            ) => {}
701	            _ => return Err(OverrideError::TypeNotScalar),
702	        }
703	
704	        if let Some(init) = o.init {
705	            if !gctx.compare_types(&TypeResolution::Handle(o.ty), &mod_info[init]) {
706	                return Err(OverrideError::InvalidType);
707	            }
708	        } else if self.overrides_resolved {
709	            return Err(OverrideError::UninitializedOverride);
710	        }
711	
712	        Ok(())
713	    }
714	
715	    /// Check the given module to be valid.
716	    pub fn validate(
717	        &mut self,
718	        module: &crate::Module,
719	    ) -> Result<ModuleInfo, WithSpan<ValidationError>> {
720	        self.overrides_resolved = false;
721	        self.validate_impl(module)
722	    }
723	
724	    /// Check the given module to be valid, requiring overrides to be resolved.
725	    ///
726	    /// This is the same as [`validate`], except that any override
727	    /// whose value is not a fully-evaluated constant expression is
728	    /// treated as an error.
729	    ///
730	    /// [`validate`]: Validator::validate
731	    pub fn validate_resolved_overrides(
732	        &mut self,
733	        module: &crate::Module,
734	    ) -> Result<ModuleInfo, WithSpan<ValidationError>> {
735	        self.overrides_resolved = true;
736	        self.validate_impl(module)
737	    }
738	
739	    fn validate_impl(
740	        &mut self,
741	        module: &crate::Module,
742	    ) -> Result<ModuleInfo, WithSpan<ValidationError>> {
743	        self.reset();
744	        self.reset_types(module.types.len());
745	
746	        Self::validate_module_handles(module).map_err(|e| e.with_span())?;
747	
748	        self.layouter.update(module.to_ctx()).map_err(|e| {
749	            let handle = e.ty;
750	            ValidationError::from(e).with_span_handle(handle, &module.types)
751	        })?;
752	
753	        // These should all get overwritten.
754	        let placeholder = TypeResolution::Value(crate::TypeInner::Scalar(crate::Scalar {
755	            kind: crate::ScalarKind::Bool,
756	            width: 0,
757	        }));
758	
759	        let mut mod_info = ModuleInfo {
760	            type_flags: Vec::with_capacity(module.types.len()),
761	            functions: Vec::with_capacity(module.functions.len()),
762	            entry_points: Vec::with_capacity(module.entry_points.len()),
763	            const_expression_types: vec![placeholder; module.global_expressions.len()]
764	                .into_boxed_slice(),
765	        };
766	
767	        for (handle, ty) in module.types.iter() {
768	            let ty_info = self
769	                .validate_type(handle, module.to_ctx())
770	                .map_err(|source| {
771	                    ValidationError::Type {
772	                        handle,
773	                        name: ty.name.clone().unwrap_or_default(),
774	                        source,
775	                    }
776	                    .with_span_handle(handle, &module.types)
777	                })?;
778	            debug_assert!(
779	                ty_info.flags.contains(TypeFlags::CONSTRUCTIBLE)
780	                    == module.types[handle].inner.is_constructible(&module.types)
781	            );
782	            mod_info.type_flags.push(ty_info.flags);
783	            self.types[handle.index()] = ty_info;
784	        }
785	
786	        {
787	            let t = crate::Arena::new();
788	            let resolve_context = crate::proc::ResolveContext::with_locals(module, &t, &[]);
789	            for (handle, _) in module.global_expressions.iter() {
790	                mod_info
791	                    .process_const_expression(handle, &resolve_context, module.to_ctx())
792	                    .map_err(|source| {
793	                        ValidationError::ConstExpression { handle, source }
794	                            .with_span_handle(handle, &module.global_expressions)
795	                    })?
796	            }
797	        }
798	
799	        let global_expr_kind = ExpressionKindTracker::from_arena(&module.global_expressions);
800	
801	        if self.flags.contains(ValidationFlags::CONSTANTS) {
802	            for (handle, _) in module.global_expressions.iter() {
803	                self.validate_const_expression(
804	                    handle,
805	                    module.to_ctx(),
806	                    &mod_info,
807	                    &global_expr_kind,
808	                )
809	                .map_err(|source| {
810	                    ValidationError::ConstExpression { handle, source }
811	                        .with_span_handle(handle, &module.global_expressions)
812	                })?
813	            }
814	
815	            for (handle, constant) in module.constants.iter() {
816	                self.validate_constant(handle, module.to_ctx(), &mod_info, &global_expr_kind)
817	                    .map_err(|source| {
818	                        ValidationError::Constant {
819	                            handle,
820	                            name: constant.name.clone().unwrap_or_default(),
821	                            source,
822	                        }
823	                        .with_span_handle(handle, &module.constants)
824	                    })?
825	            }
826	
827	            for (handle, r#override) in module.overrides.iter() {
828	                self.validate_override(handle, module.to_ctx(), &mod_info)
829	                    .map_err(|source| {
830	                        ValidationError::Override {
831	                            handle,
832	                            name: r#override.name.clone().unwrap_or_default(),
833	                            source,
834	                        }
835	                        .with_span_handle(handle, &module.overrides)
836	                    })?;
837	            }
838	        }
839	
840	        for (var_handle, var) in module.global_variables.iter() {
841	            self.validate_global_var(var, module.to_ctx(), &mod_info, &global_expr_kind)
842	                .map_err(|source| {
843	                    ValidationError::GlobalVariable {
844	                        handle: var_handle,
845	                        name: var.name.clone().unwrap_or_default(),
846	                        source,
847	                    }
848	                    .with_span_handle(var_handle, &module.global_variables)
849	                })?;
850	        }
851	
852	        for (handle, fun) in module.functions.iter() {
853	            match self.validate_function(fun, module, &mod_info, false) {
854	                Ok(info) => mod_info.functions.push(info),
855	                Err(error) => {
856	                    return Err(error.and_then(|source| {
857	                        ValidationError::Function {
858	                            handle,
859	                            name: fun.name.clone().unwrap_or_default(),
860	                            source,
861	                        }
862	                        .with_span_handle(handle, &module.functions)
863	                    }))
864	                }
865	            }
866	        }
867	
868	        let mut ep_map = FastHashSet::default();
869	        for ep in module.entry_points.iter() {
870	            if !ep_map.insert((ep.stage, &ep.name)) {
871	                return Err(ValidationError::EntryPoint {
872	                    stage: ep.stage,
873	                    name: ep.name.clone(),
874	                    source: EntryPointError::Conflict,
875	                }
876	                .with_span()); // TODO: keep some EP span information?
877	            }
878	
879	            match self.validate_entry_point(ep, module, &mod_info) {
880	                Ok(info) => mod_info.entry_points.push(info),
881	                Err(error) => {
882	                    return Err(error.and_then(|source| {
883	                        ValidationError::EntryPoint {
884	                            stage: ep.stage,
885	                            name: ep.name.clone(),
886	                            source,
887	                        }
888	                        .with_span()
889	                    }));
890	                }
891	            }
892	        }
893	
894	        Ok(mod_info)
895	    }
896	}
897	
898	fn validate_atomic_compare_exchange_struct(
899	    types: &crate::UniqueArena<crate::Type>,
900	    members: &[crate::StructMember],
901	    scalar_predicate: impl FnOnce(&crate::TypeInner) -> bool,
902	) -> bool {
903	    members.len() == 2
904	        && members[0].name.as_deref() == Some("old_value")
905	        && scalar_predicate(&types[members[0].ty].inner)
906	        && members[1].name.as_deref() == Some("exchanged")
907	        && types[members[1].ty].inner == crate::TypeInner::Scalar(crate::Scalar::BOOL)
908	}
