  │
  = note: `cross` accepts the following types for argument #1:
  = note: allowed type: vec3<{AbstractFloat}>
  = note: allowed type: vec3<f32>
  = note: allowed type: vec3<f16>
  = note: allowed type: vec3<f64>

",
    );
}

#[test]
fn type_not_constructible() {
    check(
        r#"
            fn x() {
