  │
3 │                 _ = mat2x2<f32>(array(0, 1), vec2(2, 3));
  │                     ^^^^^^^^^^^ ^^^^^^^^^^^ this expression has type array<{AbstractInt}, 2>
  │                     │\x20\x20\x20\x20\x20\x20\x20\x20\x20\x20\x20\x20
